import { G, T, A, O, P } from './domains.js';

export const part5 = [
  {id:505,domain:G,question:"What is a rainbow table?",options:["A color-coded metrics dashboard","A hash-to-password lookup table","A multi-dimensional encryption scheme","A key management reference table"],answer:1,explanation:"Rainbow tables enable fast reverse hash lookups — defeated by salting (adding unique random values to each password before hashing makes precomputation impractical).",optionExplanations:["This is a reporting dashboard, unrelated to hashing.","A rainbow table maps hashes back to plaintext for fast cracking.","This describes layered encryption, not a lookup table.","This is key inventory management, not password cracking."]},
  {id:506,domain:O,question:"What is the purpose of an emergency response plan?",options:["Procedures for responding to various emergencies","An outage communication protocol","A building fire evacuation plan","A plan covering only natural disasters"],answer:0,explanation:"Emergency response plans define roles, communication trees, decision authorities, and action steps for multiple scenarios — integrating with BCP and DRP for comprehensive resilience.",optionExplanations:["It covers multiple emergency types with defined roles and actions.","This is IT outage communication, a narrower subset.","This is a fire evacuation plan, one physical safety subset.","This wrongly limits scope to natural disasters only."]},
  {id:507,domain:T,question:"What is pharming?",options:["Redirecting users through DNS tampering","Scraping personal data from social media","Attacks on agricultural control systems","Outsourcing attacks to criminal services"],answer:0,explanation:"Unlike phishing, pharming doesn't require a malicious link — victims type the legitimate URL but DNS corruption or hosts file modification sends them to an attacker's site.",optionExplanations:["Pharming corrupts DNS or hosts files to silently redirect victims.","This is OSINT data harvesting, not pharming.","This is a critical-infrastructure attack, unrelated to pharming.","This describes crime-as-a-service, not pharming."]},
  {id:508,domain:A,question:"What is data masking?",options:["Irreversibly removing all identifying data","Encrypting data before storage","Obscuring network traffic patterns","Substituting real data with realistic fakes"],answer:3,explanation:"Data masking enables realistic development/testing with production-like data without exposing real PII or sensitive information — required for compliance in dev/test environments.",optionExplanations:["This describes anonymization, which is irreversible unlike masking.","Encryption hides but preserves the real value; masking substitutes it.","This is traffic analysis prevention, unrelated to data masking.","Masking swaps real values for realistic but fictional ones."]},
  {id:509,domain:T,question:"What is a Denial-of-Service (DoS) attack's primary goal?",options:["Gaining unauthorized system access","Intercepting communications between two parties","Overwhelming a resource to deny legitimate use","Exfiltrating sensitive files and data"],answer:2,explanation:"DoS attacks target availability — the 'A' in CIA triad. Success is measured by downtime duration and impact on business operations and reputation.",optionExplanations:["This is unauthorized access, an integrity and confidentiality attack.","This is a man-in-the-middle attack targeting confidentiality.","DoS floods or crashes a resource to deny legitimate users.","This is data theft, a confidentiality attack."]},
  {id:510,domain:G,question:"What is cryptanalysis?",options:["Analyzing ciphers to recover plaintext without the key","Designing and standardizing new encryption algorithms","Reviewing published cryptography research papers","Reverse engineering obfuscated malware samples"],answer:0,explanation:"Cryptanalysis attacks include brute force, differential cryptanalysis, linear cryptanalysis, birthday attacks, and side-channel attacks — all aimed at defeating cryptographic security.",optionExplanations:["Cryptanalysis studies weaknesses to break cryptographic systems.","This is cryptography design, the opposite of cryptanalysis.","This is academic study, not active code-breaking.","This is malware analysis, unrelated to cryptography."]},
  {id:511,domain:O,question:"What is a security information sharing community's purpose?",options:["A classified government intelligence feed","Staff exchange programs between organizations","Sharing threat intel sector-wide","A networking forum for practitioners"],answer:2,explanation:"ISACs (Information Sharing and Analysis Centers), ISAO, and private threat sharing communities help defenders benefit from each other's experiences before they're targeted.",optionExplanations:["This describes a government program, not a sharing community.","This is HR talent exchange, unrelated to threat intel.","ISACs let organizations share IoCs and defenses collectively.","This is professional networking, not operational intel sharing."]},
  {id:512,domain:T,question:"What is credential spraying?",options:["Capturing hashes over Wi-Fi","Injecting stolen credentials into SQL queries","Trying few passwords across many accounts","Reusing stolen credentials across systems"],answer:2,explanation:"Credential spraying avoids account lockouts — instead of 100 attempts on one account (which locks it), try 'Password1!' across 100 different accounts.",optionExplanations:["This is wireless credential capture, a different attack.","This is SQL injection, not credential spraying.","Spraying tests common passwords broadly to avoid lockouts.","This is lateral movement with reused credentials, not spraying."]},
  {id:513,domain:A,question:"What is an intrusion detection system (IDS) anomaly detection mode?",options:["Alerting on deviations from a normal baseline","Allowing only pre-approved traffic sources","Matching traffic against known attack signatures","Detecting unusual hardware temperature or power use"],answer:0,explanation:"Anomaly-based detection catches zero-days and insider threats that have no signatures — at the cost of higher false positive rates when legitimate behavior deviates from the baseline.",optionExplanations:["Anomaly detection flags statistical deviation from learned normal behavior.","This is allowlist-based access control, not anomaly detection.","This is signature-based detection, the opposite approach.","This is physical hardware monitoring, unrelated to IDS."]},
  {id:514,domain:P,question:"What is the storage limitation principle in data privacy?",options:["Deleting data once no longer needed","Capping the data volume per individual","Requiring all data stay on-premises","Requiring all data live in one database"],answer:0,explanation:"GDPR Article 5(1)(e) mandates storage limitation — customer purchase data needed for 7-year tax compliance must be deleted at 7 years, not kept indefinitely.",optionExplanations:["Data should only be kept identifiable as long as necessary.","This is a storage quota, not a retention rule.","This is data residency, unrelated to retention duration.","This is centralization, unrelated to how long data is kept."]},
  {id:515,domain:G,question:"What is a digital signature?",options:["A typed name or click-to-sign button","A private-key-based proof of identity and integrity","A PIN approving a document workflow","A scanned image of a handwritten signature"],answer:1,explanation:"Digital signatures (RSA, ECDSA) provide authentication (who signed it), integrity (the content wasn't changed), and non-repudiation (the signer cannot deny signing).",optionExplanations:["This is a broad e-signature concept, not cryptographic.","Digital signatures use private keys to prove sender and integrity.","A PIN is an authentication factor, not a signature.","A scanned image has no cryptographic proof of authenticity."]},
  {id:516,domain:T,question:"What is a smishing attack?",options:["In-person contact followed by phishing email","A slow, low-volume phishing campaign","Phishing conducted via SMS text messages","Phishing using emoji and friendly tone"],answer:2,explanation:"Smishing exploits SMS's perceived trustworthiness — people are more likely to click text message links than email links, and mobile users often can't inspect URLs before clicking.",optionExplanations:["This describes pretexting, not smishing.","This is a timing evasion strategy, not SMS-based.","Smishing delivers phishing links through text messages.","Tone and emoji don't define smishing; the SMS channel does."]},
  {id:517,domain:A,question:"What is a cloud workload protection platform (CWPP)?",options:["Protecting workloads across environments","A cloud cost optimization platform","A cloud observability and tracing platform","An infrastructure-as-code orchestration tool"],answer:0,explanation:"CWPPs (Prisma Cloud, Defender for Cloud) apply runtime protection, vulnerability management, and behavioral monitoring to cloud workloads regardless of where they run.",optionExplanations:["CWPPs protect VMs, containers, and serverless across environments.","This is FinOps cost tracking, not workload security.","This is performance observability, not security protection.","This is deployment orchestration, not workload protection."]},
  {id:518,domain:O,question:"What is the difference between a full backup and an incremental backup?",options:["Full runs weekly, incremental runs monthly","Copies everything vs. only changes","Full encrypts data, incremental sends plaintext","Incremental backups are inherently more secure"],answer:1,explanation:"Full: simple recovery (restore one backup) but slow and storage-intensive. Incremental: fast and efficient but complex recovery (restore full + all incrementals in order).",optionExplanations:["Scheduling frequency is policy, not the defining difference.","Full backs up all data; incremental backs up only changes.","Encryption should apply to both backup types equally.","Backup type affects size and speed, not inherent security."]},
  {id:519,domain:T,question:"What is a man-in-the-middle attack using SSL stripping?",options:["Removing TLS libraries from a victim's device","Downgrading HTTPS to HTTP during connection setup","Revoking certificates to force plaintext HTTP","Decrypting files stored on a device"],answer:1,explanation:"SSL stripping intercepts the user's initial HTTP request before the server can redirect to HTTPS, serving HTTP while maintaining HTTPS with the server — the user is unaware they're unprotected.",optionExplanations:["This requires device access; stripping works over the network.","The attacker intercepts before the HTTPS redirect completes.","This is certificate management, not a network interception attack.","This is storage decryption, unrelated to transport hijacking."]},
  {id:520,domain:G,question:"What is the OWASP Top 10?",options:["A ranking of top security vendors","A list of top web app risks","A mandatory ten-control compliance framework","A ranking of dangerous threat actor groups"],answer:1,explanation:"OWASP Top 10 (injection, broken auth, sensitive data exposure, XSS, etc.) is the most referenced web security standard — many compliance frameworks require addressing it.",optionExplanations:["This is a commercial analyst report, not OWASP's list.","The OWASP Top 10 catalogs the most impactful web app risks.","It's awareness guidance, not a regulatory mandate.","This ranks threat actors, not vulnerability categories."]},
  {id:521,domain:O,question:"What is a red team engagement?",options:["A competitive capture-the-flag exercise","A simulated real-world adversary attack","A dedicated incident response team","A monthly emergency notification drill"],answer:1,explanation:"Red teams go beyond point-in-time penetration tests — they simulate entire attack campaigns (initial access, lateral movement, data exfiltration) over weeks or months.",optionExplanations:["CTFs are competitions, not adversary simulations against one org.","Red teams simulate real adversaries to test detection and response.","This describes the blue team, not the red team.","This tests notification procedures, not offensive simulation."]},
  {id:522,domain:T,question:"What is a keylogger?",options:["A log of physical badge access events","A password manager auto-fill tool","Software or hardware recording keystrokes","A vault storing cryptographic keys"],answer:2,explanation:"Hardware keyloggers plug between keyboard and PC; software keyloggers run as processes — both capture everything typed including passwords and sensitive data.",optionExplanations:["This is a physical access log, unrelated to keystrokes.","Password managers store credentials; keyloggers steal them.","Keyloggers capture typed input like passwords and card numbers.","This describes a key management system, not a keylogger."]},
  {id:523,domain:A,question:"What is cloud-native security?",options:["Security for natively compiled cloud languages","Cloud-built security tools and automation","Hardening apps written in Go or Rust","Built-in provider security features like IAM"],answer:1,explanation:"Cloud-native security uses IaC scanning, CSPM, CWPP, and cloud API integration — traditional perimeter tools can't inspect API calls and serverless function invocations.",optionExplanations:["This is language-specific, a narrower concern.","Cloud-native security uses automation and APIs suited to cloud scale.","This is language choice, not a security architecture.","Native CSP features are one part, not the whole approach."]},
  {id:524,domain:P,question:"What is the accountability principle in data privacy?",options:["Controllers must demonstrate compliance with privacy rules","Processors must follow controller instructions","Fines imposed for data protection violations","Holding individual employees personally liable for breaches"],answer:0,explanation:"GDPR accountability (Article 5(2)) requires controllers to not only comply but to demonstrate compliance — through DPIAs, records of processing, policies, and DPO appointment.",optionExplanations:["Accountability requires proving compliance, not just achieving it.","This is a processor obligation under Article 28.","This is an enforcement penalty, not the principle itself.","This is individual liability, distinct from organizational accountability."]},
  {id:525,domain:G,question:"What is entropy in cryptography?",options:["The computational work factor of an algorithm","A measure of randomness and unpredictability","Bit-pattern disorder within key material","Power consumed running cryptographic operations"],answer:1,explanation:"Low entropy (predictable seeds) leads to weak keys — the Debian OpenSSL bug (2008) that limited random number generation to 32,768 possible values made all generated keys predictable.",optionExplanations:["This is algorithmic complexity, not randomness quality.","High entropy is essential for generating strong keys.","Disorder alone isn't the definition; unpredictability is.","This is energy use, unrelated to cryptographic entropy."]},
  {id:526,domain:O,question:"What is security hardening?",options:["Reducing attack surface via secure configuration","Manufacturing tamper-resistant physical enclosures","Tightening firewall rule sets","Upgrading to stronger encryption algorithms"],answer:0,explanation:"Hardening follows CIS Benchmarks or DISA STIGs — disabling Telnet, removing default passwords, patching, disabling USB ports, and configuring required services securely.",optionExplanations:["Hardening disables unneeded services and closes unused ports.","This is physical hardware engineering, not system hardening.","This is one hardening activity, not the whole practice.","Encryption upgrades are one part of broader hardening."]},
  {id:527,domain:T,question:"What is living-off-the-land (LotL) binaries (LOLBins)?",options:["Trusted binaries abused for malicious use","Binaries running on on-premises servers","Executables used in agricultural equipment","Placing data centers on rural land"],answer:0,explanation:"LOLBins are trusted Windows/Linux binaries signed by Microsoft or the OS vendor — security tools often whitelist them, making them ideal for bypass.",optionExplanations:["LOLBins like certutil and regsvr32 are trusted but abused.","This is a deployment model, not LOLBins.","This is unrelated agricultural technology.","This is facility siting, unrelated to LOLBins."]},
  {id:528,domain:A,question:"What is application segmentation?",options:["Deploying workloads across cloud regions","Isolating app tiers into separate network zones","Grouping users by role-based permissions","Splitting source code into modules"],answer:1,explanation:"Three-tier segmentation (DMZ for web → App tier behind firewall → DB tier on isolated network) ensures database servers are never directly reachable from the internet.",optionExplanations:["This is geographic distribution, a cloud availability concern.","Segmentation isolates web, app, and database tiers with access controls.","This is RBAC, applied within an application.","This is code modularity, a software design practice."]},
  {id:529,domain:P,question:"What is the right to access under GDPR?",options:["Public access to any organization's records","Pausing processing during a dispute","Requesting a copy of one's own data","Correcting inaccurate personal data"],answer:2,explanation:"GDPR Article 15 (Subject Access Request) gives individuals the right to know what data organizations hold about them — organizations must respond within one month.",optionExplanations:["Unrestricted public access would violate confidentiality.","This is the right to restriction, a different GDPR right.","The right of access lets individuals request a copy of their data.","This is the right to rectification, a different GDPR right."]},
  {id:530,domain:G,question:"What is a HMAC (Hash-Based Message Authentication Code)?",options:["A password-specific hashing algorithm","A PKI mechanism using certificates","A MAC address filtering policy engine","A hash combined with a secret key"],answer:3,explanation:"HMACs (HMAC-SHA256) add a secret key to hashing — without the key, an attacker cannot create a valid HMAC even if they know the hash algorithm.",optionExplanations:["This describes bcrypt-style password hashing, not HMAC.","PKI uses certificates; HMAC uses a shared secret key instead.","This is network MAC filtering, unrelated to cryptographic MACs.","HMAC combines a hash function with a secret key for authenticity."]},
  {id:531,domain:T,question:"What is a cryptojacking attack?",options:["Hacking cryptocurrency exchanges","Hijacking devices to mine crypto","Stealing private keys from wallets","Exploiting smart contract bugs"],answer:1,explanation:"Cryptojacking degrades victim system performance while generating cryptocurrency profit for attackers — delivered via malicious websites (browser mining) or malware.",optionExplanations:["This targets exchanges directly, not victim devices.","Cryptojacking secretly uses CPU and GPU power to mine coins.","This is wallet theft, not resource hijacking.","This is DeFi exploitation, unrelated to cryptojacking."]},
  {id:532,domain:A,question:"What is a next-generation firewall (NGFW)?",options:["A cloud-native virtualized firewall","A firewall with app awareness and intrusion prevention","A firewall on specialized high-throughput hardware","A firewall using ML for autonomous decisions"],answer:1,explanation:"NGFWs (Palo Alto, Fortinet) identify applications regardless of port — 'allow Facebook but block Facebook Games' — and correlate traffic with user identities from directory services.",optionExplanations:["This describes deployment form factor, not NGFW capability.","NGFWs add deep inspection, app awareness, and identity to filtering.","Hardware specs don't define NGFW classification.","AI decisioning may be a feature, not the definition."]},
  {id:533,domain:O,question:"What is continuous integration/continuous deployment (CI/CD) security?",options:["Embedding security engineers in sprint teams","Keeping deployment schedules uninterrupted","Automatically deploying patches to systems","Securing the build and deploy pipeline"],answer:3,explanation:"CI/CD pipeline attacks (like SolarWinds) compromise build systems to inject malicious code — security includes signed commits, SAST scanning, secret detection, and artifact signing.",optionExplanations:["This is DevSecOps culture, a related but broader practice.","This is release cadence, not pipeline security.","Patch automation is one use case, not the full scope.","It protects the pipeline from code commit to deployment."]},
  {id:534,domain:T,question:"What is a rootkit's primary defense evasion technique?",options:["Signing malware with stolen certificates","Renaming processes to mimic system ones","Hiding its presence via OS subversion","Encrypting payloads to evade signatures"],answer:2,explanation:"Kernel-level rootkits (ring 0) hook system calls, modifying what the OS reports to security tools — making files, processes, and network connections invisible.",optionExplanations:["This is certificate abuse, a separate evasion technique.","This is masquerading, a lighter evasion method.","Rootkits hook OS calls so tools can't see them.","This is packing or obfuscation, a different evasion technique."]},
  {id:535,domain:G,question:"What is end-to-end encryption (E2EE)?",options:["Encrypting data at rest and in transit","Encrypting an entire storage device","Only endpoints can decrypt the message","Encrypting traffic between client and server with TLS"],answer:2,explanation:"E2EE (Signal, WhatsApp, ProtonMail) means the service provider cannot read your messages even if legally compelled — keys exist only on endpoint devices.",optionExplanations:["This is general data protection, not endpoint-only encryption.","This is full disk encryption, protecting data at rest.","E2EE keeps keys only on sender and receiver devices.","TLS lets the server decrypt; E2EE keeps it from the provider."]},
  {id:536,domain:P,question:"What is a data breach notification requirement?",options:["Marketing new products to customers","An internal technical incident report","Legally informing individuals and regulators of a breach","A mandatory public media announcement"],answer:2,explanation:"GDPR requires notification to supervisory authority within 72 hours and to affected individuals 'without undue delay' — many US states have similar laws with varying timeframes.",optionExplanations:["This is marketing, unrelated to breach notification law.","This is internal documentation, not external notification.","Laws require notifying affected people and regulators within set timeframes.","Media disclosure is voluntary, not the legal requirement."]},
  {id:537,domain:A,question:"What is a secure enclave?",options:["A physically secured data center room","A processor's isolated execution environment","A tamper-resistant HSM for key storage","A logically segmented network zone"],answer:1,explanation:"Intel SGX, AMD SEV, and ARM TrustZone create isolated memory regions — even the hypervisor or OS cannot inspect enclave memory, enabling confidential cloud computing.",optionExplanations:["This is a physical facility control, not a processor feature.","Secure enclaves protect code and data from the host OS.","HSMs are dedicated key hardware, distinct from enclaves.","This is network segmentation, not processor isolation."]},
  {id:538,domain:O,question:"What is the purpose of a configuration management database (CMDB)?",options:["A database of firewall and endpoint policies","A database admin monitoring console","A repository of IT assets and links","Versioned database server configuration files"],answer:2,explanation:"CMDBs enable impact analysis (what does changing this server affect?), support incident investigation (what changed recently?), and maintain the asset inventory security teams need.",optionExplanations:["This stores security policies, not general asset records.","This is DBA tooling, not asset management.","A CMDB tracks assets and relationships for change and incident management.","This is config file storage, a narrower DevOps task."]},
  {id:539,domain:T,question:"What is a multi-vector attack?",options:["Routing traffic through multiple proxies","A worm spreading across network segments","Combining multiple techniques and channels at once","A campaign targeting many organizations at once"],answer:2,explanation:"Modern attacks rarely use a single technique — phishing delivers ransomware that exploits a vulnerability during installation while C2 uses legitimate cloud services to evade detection.",optionExplanations:["This is an evasion technique, not a multi-vector attack.","This is worm propagation, a single spreading mechanism.","Multi-vector attacks combine phishing, exploits, and more simultaneously.","This is campaign breadth, not technique diversity."]},
  {id:540,domain:G,question:"What is post-quantum cryptography (PQC)?",options:["Cryptography run on quantum hardware","Algorithms planned for future quantum deployment","Classical algorithms resistant to quantum attacks","Quantum key distribution over communication channels"],answer:2,explanation:"NIST PQC standards (CRYSTALS-Kyber, CRYSTALS-Dilithium, SPHINCS+) selected in 2024 replace RSA/ECC which quantum computers can break using Shor's algorithm.",optionExplanations:["PQC runs on classical hardware, not quantum computers.","PQC is deployed today, not reserved for the future.","PQC uses math problems hard for quantum computers to solve.","QKD uses quantum physics; PQC uses classical math instead."]},
  {id:541,domain:T,question:"What is a drive-by cryptomining attack?",options:["Mobile apps that mine cryptocurrency","Relocating hardware for cheap electricity","Installed mining software via a browser exploit","Browser JavaScript mining on page visit"],answer:3,explanation:"Browser-based miners (Coinhive was infamous) run without installation — any browser visiting the page mines cryptocurrency, often going undetected except for high CPU usage.",optionExplanations:["This targets mobile apps specifically, not browser visits.","This is legitimate cost optimization, not an attack.","This requires installation; drive-by mining needs none.","The script runs automatically in the browser with no install."]},
  {id:542,domain:A,question:"What is software composition analysis (SCA)?",options:["Finding vulnerable open-source components","Analyzing development team staffing levels","Manually reviewing software architecture and data flows","Comparing licensing costs of software options"],answer:0,explanation:"SCA tools (Snyk, Black Duck, Dependabot) identify vulnerable open source libraries before attackers exploit them — Log4Shell affected millions of apps using Log4j.",optionExplanations:["SCA scans code for open-source libraries and known CVEs.","This is workforce management, unrelated to code analysis.","This is manual threat modeling, not automated SCA.","This is procurement cost analysis, not vulnerability scanning."]},
  {id:543,domain:O,question:"What is a penetration test report?",options:["An expense reimbursement request","Findings, evidence, risk ratings, and remediation steps","A certificate confirming testing occurred","A network performance measurement report"],answer:1,explanation:"Pentest reports provide technical findings for IT teams (reproduction steps, payloads) and executive summaries for leadership (risk ratings, business impact, prioritized recommendations).",optionExplanations:["This is a billing document, not the technical deliverable.","The report documents vulnerabilities, evidence, and how to fix them.","A certificate confirms completion but has no technical findings.","This measures throughput, unrelated to security testing."]},
  {id:544,domain:P,question:"What is data classification?",options:["Sorting data by creation or access date","Categorizing data by sensitivity level","Categorizing transactions for tax reporting","Designing normalized database schemas"],answer:1,explanation:"Data classification (Public, Internal, Confidential, Restricted/Top Secret) drives security controls — unclassified data gets minimal protection; restricted data gets the strongest.",optionExplanations:["This is records lifecycle management, not sensitivity categorization.","Classification labels determine required handling and protection controls.","This is tax categorization, unrelated to data security.","This is database design, not security governance."]},
  {id:545,domain:G,question:"What is block cipher mode of operation?",options:["The CPU privilege level during encryption","How a cipher processes data beyond one block","Whether encryption uses hardware or software offload","Which cipher suites a device offers in TLS"],answer:1,explanation:"ECB (never use — reveals patterns), CBC (sequential, needs IV), CTR (parallel, stream-like), GCM (provides both encryption and integrity) each have different security properties.",optionExplanations:["CPU privilege rings are unrelated to cipher chaining.","Modes like CBC and GCM define how blocks are chained.","This is an implementation choice, not the mode itself.","This is cipher suite configuration, a separate concept."]},
  {id:546,domain:T,question:"What is an insider threat?",options:["Any attacker who gained network access","External phishing targeting employees","Threats from competitor employees externally","Threats from those with internal access"],answer:3,explanation:"Insider threats are particularly dangerous because they bypass perimeter controls — they have legitimate access and knowledge of sensitive systems and data locations.",optionExplanations:["This includes external attackers, broader than insider threats.","This is social engineering by an outsider, not an insider.","This describes external actors, not internal ones.","Insiders misuse legitimate access they already have."]},
  {id:547,domain:A,question:"What is a content delivery network (CDN) and its security benefits?",options:["An internal network distributing corporate files","A distributed server network with DDoS mitigation","A content management publishing platform","A network for encrypted DRM media streaming"],answer:1,explanation:"CDNs (Cloudflare, Akamai, Fastly) absorb DDoS attacks through distributed capacity, hide origin server IPs, and can enforce WAF and bot mitigation policies globally.",optionExplanations:["This is an internal distribution network, not a public CDN.","CDNs absorb DDoS traffic and hide origin servers.","This is a CMS, unrelated to content delivery infrastructure.","This is a specialized media use case, not general CDN security."]},
  {id:548,domain:O,question:"What is a business continuity plan (BCP)?",options:["A contingency plan for failed business strategy","Keeping functions running through disruption","A market expansion and growth strategy","A fire evacuation procedure"],answer:1,explanation:"BCPs address all aspects of business survival during disruptions — who does what, where teams work if offices are inaccessible, how customers are served, and how systems are restored.",optionExplanations:["This is strategic pivoting, not operational continuity.","BCPs keep essential functions running during disruptions.","This is growth strategy, unrelated to continuity.","This is one narrow emergency procedure, not the full BCP."]},
  {id:549,domain:T,question:"What is a Slowloris attack?",options:["Holding connections open with partial requests","Slow port scanning to evade detection","Delaying login attempts to avoid lockout","Routing traffic through slow connections"],answer:0,explanation:"Slowloris keeps many HTTP connections open with partial headers, never completing them — the server holds connections indefinitely, exhausting its connection limit and denying service to legitimate users.",optionExplanations:["Slowloris exhausts connection pools with incomplete requests.","This is stealthy reconnaissance, not a DoS technique.","This is slow brute-forcing, a different attack.","This is a vague evasion idea, not the actual technique."]},
  {id:550,domain:G,question:"What is a security token?",options:["A certificate embedded during manufacturing","A physical badge for building access","A session ID stored in a cookie","A device generating one-time passwords"],answer:3,explanation:"Hardware tokens (RSA SecurID, YubiKey) and software tokens (TOTP apps like Google Authenticator) provide the 'something you have' factor in MFA — without physical possession, authentication fails.",optionExplanations:["This is device attestation, not user authentication.","This is a physical access card, not an MFA device.","This is a web session identifier, not an MFA token.","Security tokens provide the possession factor via OTPs or keys."]},
  {id:551,domain:O,question:"What is DevSecOps?",options:["Integrating security throughout the DevOps pipeline","A dedicated separate security review team","Security ops adopting DevOps chat tools","Hardening CI/CD infrastructure specifically"],answer:0,explanation:"DevSecOps shifts security left — developers run SAST scans locally, CI/CD pipelines include SCA and DAST, and infrastructure code is scanned for misconfigurations before deployment.",optionExplanations:["DevSecOps embeds security testing into every pipeline stage.","This is a separate team, not pipeline integration.","This is tooling adoption, not cultural integration.","This is one piece, not the full DevSecOps practice."]},
  {id:552,domain:T,question:"What is a macro virus?",options:["Malicious code in document macros","A self-propagating network worm","A virus affecting camera firmware","A virus defined by large file size"],answer:0,explanation:"Macro viruses were rampant in the 1990s (Melissa virus) and have resurged through malicious Office documents — often delivered via email to bypass perimeter controls.",optionExplanations:["Macro viruses execute when a document's macros are enabled.","This describes a worm, not a macro virus.","This is unrelated hardware firmware, not documents.","File size doesn't define macro viruses; scripting language does."]},
  {id:553,domain:A,question:"What is a security testing tool DAST (Dynamic Application Security Testing)?",options:["A database-focused security assessment","IDE-integrated static source code scanning","Testing a live app via simulated attacks","Developers watching live sessions for bugs"],answer:2,explanation:"DAST tools (OWASP ZAP, Burp Suite) test the application as an attacker would — finding XSS, SQL injection, authentication flaws, and configuration issues that static analysis misses.",optionExplanations:["This is a specialized database test, not general DAST.","This is SAST, the static counterpart to DAST.","DAST probes the running application from the outside.","This is a collaborative practice, not automated testing."]},
  {id:554,domain:P,question:"What is a Subject Access Request (SAR) under GDPR?",options:["A request for elevated system access","A request to stop processing data","Requesting a copy of held personal data","A request to port data to a competitor"],answer:2,explanation:"Organizations must respond to SARs within one month, provide a copy of all held data, explain processing purposes and legal basis, and describe any third-party recipients.",optionExplanations:["This is an IT access request, unrelated to privacy rights.","This is the right to restriction, a different request.","A SAR asks what data is held and how it's used.","This is the right to data portability, a different request."]},
  {id:555,domain:G,question:"What is the purpose of IV (Initialization Vector) in encryption?",options:["A channel for transmitting encryption keys","The parameter determining cipher strength","Powering on hardware encryption modules","A random value ensuring unique ciphertext"],answer:3,explanation:"IVs prevent patterns in encrypted output — without an IV, the same message encrypted twice produces identical ciphertext, leaking information about repeated content.",optionExplanations:["This describes key exchange, not an IV.","Key length determines strength, not the IV.","This is device setup, unrelated to IVs.","An IV keeps identical plaintexts from producing identical ciphertext."]},
  {id:556,domain:O,question:"What is a security advisory?",options:["A procurement recommendation for security tools","General best-practice guidance from agencies","Informal consultant recommendations","A formal notice of a vulnerability and its fix"],answer:3,explanation:"Security advisories (CVE descriptions, vendor bulletins like Microsoft Patch Tuesday) enable organizations to assess risk and prioritize patching before exploitation occurs.",optionExplanations:["This is a purchase recommendation, not a vulnerability notice.","This is general guidance, not a specific vulnerability disclosure.","This is informal advice, not a formal published notice.","Advisories describe a specific flaw and available mitigations."]},
  {id:557,domain:T,question:"What is a social engineering pretext?",options:["A fabricated scenario to gain a target's trust","The OSINT research phase before an attack","Introductory text preceding phishing content","Building fake sites and spoofed caller IDs"],answer:0,explanation:"A convincing pretext (impersonating IT support, an auditor, a vendor, or HR) makes targets comply with requests they'd normally question — believability is the key success factor.",optionExplanations:["The pretext is the false story used to manipulate the target.","This is reconnaissance, which supports but isn't the pretext.","This is email formatting, not the fabricated identity.","This is technical infrastructure, separate from the narrative itself."]},
  {id:558,domain:A,question:"What is an air gap?",options:["An HVAC vulnerability affecting IT equipment","Total isolation from untrusted networks","A structural gap for cable routing","Required spacing between security guards"],answer:1,explanation:"Air-gapped systems (classified networks, SCADA systems, nuclear controls) were thought impenetrable until Stuxnet demonstrated that USB drives could bridge the gap.",optionExplanations:["This is a building system flaw, unrelated to air gaps.","Air-gapped systems have no network connection to untrusted networks.","This is facilities construction, not network isolation.","This is physical security staffing, not network isolation."]},
  {id:559,domain:P,question:"What is the purpose of a consent record under GDPR?",options:["Proof that valid consent was obtained","A log confirming notices were sent","Logs of authentication and access events","A log of subject access requests"],answer:0,explanation:"GDPR requires organizations to prove they obtained valid, specific, informed consent — consent records must capture the exact consent given, when, through what mechanism, and for what purpose.",optionExplanations:["Consent records prove what was agreed to, when, and how.","This confirms delivery, not active agreement to processing.","This is security monitoring, unrelated to consent.","This tracks rights requests, a separate compliance record."]},
  {id:560,domain:G,question:"What is authenticated encryption?",options:["Encryption with built-in integrity and authenticity","Authenticating a user before encrypting their data","Requiring authentication to release a decryption key","Using certificates to authenticate parties before encrypting"],answer:0,explanation:"AES-GCM (used in TLS 1.3) provides authenticated encryption — the ciphertext includes an authentication tag that detects any modification, preventing padding oracle and bit-flipping attacks.",optionExplanations:["Modes like AES-GCM combine encryption with tamper detection.","This is an access workflow, not a cryptographic property.","This is access control over encrypted data, not the cipher mode.","This is PKI-based session setup, a different concept."]},
  {id:561,domain:T,question:"What is a network-based IDS vs. a host-based IDS (HIDS)?",options:["HIDS covers physical access, NIDS covers policy","NIDS is software, HIDS is hardware appliances","NIDS is more accurate, HIDS has more false positives","NIDS monitors network traffic, HIDS monitors host activity"],answer:3,explanation:"NIDS sees network patterns (port scans, protocol anomalies); HIDS sees what's actually happening on the host (files changed, new processes, log tampering) — together they provide comprehensive visibility.",optionExplanations:["Both are logical or software monitoring, not physical vs logical.","Both types can be software or hardware; that's not the distinction.","Accuracy depends on tuning, not the deployment type.","NIDS inspects packets while HIDS watches files, processes, and logs."]},
  {id:562,domain:A,question:"What is a security orchestration playbook?",options:["An automated SOAR alert workflow","A tabletop exercise discussion script","A SOC analyst training manual","A red vs blue purple team script"],answer:0,explanation:"SOAR playbooks automate 95% of alert responses — looking up IP reputation, quarantining endpoints, creating tickets, and notifying analysts — reducing MTTR from hours to seconds.",optionExplanations:["Playbooks automate enrichment, decisions, and response actions.","This is a discussion guide, not an automated workflow.","This is a training document, not machine-executable automation.","This is an exercise script, not SOAR automation."]},
  {id:563,domain:O,question:"What is patch management and why is it critical?",options:["Fixing bugs during development","Updating only OT and ICS firmware","Finding, testing, deploying security patches","Organizing physical patch cables"],answer:2,explanation:"Unpatched vulnerabilities are the most common attack vector — EternalBlue (WannaCry), Log4Shell, and ProxyLogon all exploited known vulnerabilities with available patches.",optionExplanations:["This is development-time bug fixing, not production patching.","This wrongly limits scope to OT devices only.","Patch management remediates known vulnerabilities before exploitation.","This is physical cable organization, unrelated to software patches."]},
  {id:564,domain:T,question:"What is a smurfing attack?",options:["Spoofed ICMP broadcasts amplifying traffic to a victim","A small skilled group coordinating an attack","Fake personas spreading disinformation online","Phishing emails using cartoon graphics"],answer:0,explanation:"Smurf attacks amplify traffic by spoofing the victim's IP in ping broadcasts — each ping to a /24 network generates 254 responses back to the victim.",optionExplanations:["Smurf attacks spoof the victim's IP in broadcast pings.","Group size doesn't define smurfing; the amplification technique does.","This is an influence operation, unrelated to smurfing.","The name is unrelated to cartoons; it's a DDoS technique."]},
  {id:565,domain:G,question:"What is a message authentication code (MAC)?",options:["A keyed hash proving integrity","A network interface's hardware address","A gateway-appended email verification code","A CA's signature on a certificate"],answer:0,explanation:"MACs (HMAC, CMAC, Poly1305) detect tampering and verify the sender has the shared secret — unlike signatures, they're symmetric, requiring both parties to share the key.",optionExplanations:["A MAC uses a shared secret key to detect tampering.","This is a Layer 2 hardware address, unrelated to auth codes.","This is an email-specific implementation, not the general primitive.","Certificate signatures use asymmetric keys, unlike a MAC's shared key."]},
  {id:566,domain:P,question:"What is the purpose of a data protection impact assessment (DPIA)?",options:["A disaster impact analysis for data centers","Assessing privacy risk before processing","Technical evaluation of storage infrastructure","Post-breach impact analysis"],answer:1,explanation:"GDPR Article 35 requires DPIAs for high-risk processing (biometrics, large-scale surveillance, systematic profiling) before implementation, not after.",optionExplanations:["This is business continuity planning, not privacy risk assessment.","DPIAs assess and mitigate privacy risk before processing begins.","This is infrastructure evaluation, unrelated to privacy risk.","This is reactive post-incident work; DPIAs are done beforehand."]},
  {id:567,domain:A,question:"What is an active directory (AD) and why is it a primary attack target?",options:["A network device monitoring platform","A directory of security team contacts","A table of active user sessions","A Windows identity service and prime attack target"],answer:3,explanation:"Controlling Active Directory means owning the entire Windows domain — attackers pursue domain dominance, targeting Domain Admins and using tools like BloodHound to map attack paths.",optionExplanations:["This is device monitoring, unrelated to identity management.","This is a contact list, not an identity service.","This is a simple session table, far narrower than AD.","Compromising AD grants control over the entire Windows domain."]},
  {id:568,domain:O,question:"What is a security exception process?",options:["A waiver from mandatory training","A process to approve policy deviations","An escalation procedure for severe incidents","Silently dismissing false-positive alerts"],answer:1,explanation:"Exception processes prevent security debt from accumulating invisibly — requiring approval (CISO, risk committee) and compensating controls ensures risk is accepted consciously, not ignored.",optionExplanations:["This is one narrow example, not the full exception process.","Exceptions document why a requirement can't be met and its compensating controls.","This is incident escalation, unrelated to policy waivers.","This is alert triage, not a formal risk-acceptance process."]},
  {id:569,domain:T,question:"What is a ZIP bomb (decompression bomb)?",options:["A compressed file containing evidence for investigators","A DoS attack flooding ZIP servers","An archive that expands to overwhelming size","A physical explosive hidden in a USB drive"],answer:2,explanation:"42.zip is a famous example — it's 42KB compressed but expands to 4.5 petabytes, causing antivirus engines that try to scan the contents to exhaust memory and crash.",optionExplanations:["This is digital evidence, unrelated to decompression bombs.","This is server flooding, not a malicious archive.","Decompression bombs crash scanners trying to expand them.","This is a fictional physical device, not a software attack."]},
  {id:570,domain:G,question:"What is PKCS (Public Key Cryptography Standards)?",options:["A NIST-mandated federal crypto standard","A proprietary RSA Security encryption format","A protocol for distributing public keys via servers","RSA's public key format standards"],answer:3,explanation:"PKCS standards (PKCS#1 RSA, PKCS#7/CMS, PKCS#8 private key, PKCS#10 CSR, PKCS#11 HSM interface, PKCS#12 certificate bundle) are foundational to PKI interoperability.",optionExplanations:["PKCS is an industry standard, not a government mandate.","PKCS became an open standard, not a proprietary product format.","This is key distribution, a narrower concept than PKCS.","PKCS defines formats like certificate requests and key bundles."]},
  {id:571,domain:T,question:"What is a cross-site request forgery (CSRF) token?",options:["A bearer token for cross-origin API access","A token encrypting form field data","A secret value validating a request's origin","A token blocking third-party cookies"],answer:2,explanation:"CSRF tokens are embedded in forms and verified server-side — a malicious site cannot read the victim's token (same-origin policy) so it cannot forge valid requests.",optionExplanations:["This is OAuth authorization, a different mechanism.","HTTPS encrypts form data; CSRF tokens don't encrypt.","CSRF tokens prove a request came from the legitimate site.","This is cookie-blocking, a browser privacy feature."]},
  {id:572,domain:A,question:"What is security information lifecycle management?",options:["A schedule for replacing security tools","Managing security staff hiring and offboarding","Managing encryption key rotation and destruction","Managing security data's full lifecycle"],answer:3,explanation:"Information lifecycle management ensures logs are retained long enough for investigations, security data is protected from tampering, and information is disposed of securely when no longer needed.",optionExplanations:["This is technology refresh planning, not data lifecycle.","This is HR management, unrelated to security data.","This is key lifecycle management, a narrower cryptographic process.","It covers logs, incidents, and intel from creation to disposal."]},
  {id:573,domain:O,question:"What is the MITRE ATT&CK framework?",options:["A knowledge base of attacker TTPs","A framework for securing MITRE's own network","A vulnerability severity scoring system","A framework tracking staff certifications"],answer:0,explanation:"ATT&CK (Adversarial Tactics, Techniques & Common Knowledge) provides a common language for describing attacks — detection engineers write rules against specific technique IDs, red teams plan engagements against ATT&CK tactics.",optionExplanations:["ATT&CK catalogs real-world attacker TTPs for defense planning.","ATT&CK serves the broader community, not just MITRE.","This is CVSS, a different scoring framework.","This is certification tracking, unrelated to threat intel."]},
  {id:574,domain:T,question:"What is session hijacking?",options:["Stealing a session token to impersonate a user","Joining a video call using its meeting ID","Remotely controlling a desktop after phishing credentials","Redirecting a session via DNS or BGP hijacking"],answer:0,explanation:"Session tokens stolen via XSS, network interception, or prediction are used to impersonate authenticated users — prevented by secure, HttpOnly, SameSite cookies and short session timeouts.",optionExplanations:["The stolen token lets an attacker impersonate the user.","This is meeting intrusion, unrelated to web sessions.","This is remote desktop takeover, a different attack.","This is network-level redirection, not direct token theft."]},
  {id:575,domain:G,question:"What is the purpose of a Master Boot Record (MBR) and the UEFI threat to it?",options:["A log of admin password attempts","The primary OS configuration file","The disk sector bootkits target to persist","A PXE boot network vulnerability"],answer:2,explanation:"MBR bootkits (TDL4, MBRFilter target) persist even after OS reinstallation since the MBR is written before the OS. UEFI Secure Boot was designed to address this threat.",optionExplanations:["This is an auth log, unrelated to boot sectors.","This is OS config data, not the boot sector itself.","Bootkits infect the MBR to survive OS reinstallation.","This is a network-based flaw; MBR attacks are local."]},
  {id:576,domain:P,question:"What is the principle of transparency in data privacy?",options:["Making all organizational data public","Publicly disclosing every security incident","Using publicly documented cryptographic algorithms","Being clear about how personal data is used"],answer:3,explanation:"Transparency requires plain-language privacy notices, not legal jargon — individuals must genuinely understand what happens to their data to make meaningful choices.",optionExplanations:["This would violate confidentiality, not fulfill transparency.","This is breach disclosure, a narrower legal obligation.","This is Kerckhoffs' principle, a cryptographic design concept.","Transparency means informing individuals clearly about data practices."]},
  {id:577,domain:A,question:"What is a threat model?",options:["A profile of a physical threat actor","Analyzing a system's threats and mitigations","A budget model for security spending","A summary of industry threat trends"],answer:1,explanation:"Threat modeling (STRIDE, PASTA, DREAD) asks 'what could go wrong?' for a specific system during design — finding architectural flaws when they're cheap to fix.",optionExplanations:["This is physical security intelligence, not a technical model.","Threat modeling finds design flaws from an adversary's perspective.","This is financial planning, unrelated to threat modeling.","This is a strategic overview, not a system-specific analysis."]},
  {id:578,domain:O,question:"What is a bug bounty program?",options:["Paying researchers for responsible disclosure","Rewarding QA testers for finding defects","A government reward for reporting malware","Bonuses for developers who fix the most bugs"],answer:0,explanation:"Bug bounties (HackerOne, Bugcrowd, company programs) cost less than undiscovered breaches — researchers are incentivized to report rather than exploit or sell vulnerabilities.",optionExplanations:["Bug bounties pay external researchers to report vulnerabilities responsibly.","This is internal QA incentive, not external security research.","This is a government program, distinct from bug bounties.","This is an internal developer incentive, not external researcher rewards."]},
  {id:579,domain:T,question:"What is a rootkit's persistence mechanism?",options:["Registering as a restarting scheduled task","Hooking OS functions or firmware to survive reboots","Copying itself across many directories","Creating hidden backdoor admin accounts"],answer:1,explanation:"Firmware rootkits (like LoJax in UEFI firmware) survive complete drive wiping and OS reinstallation because they reside in flash storage outside the operating system.",optionExplanations:["This is visible and easily removed, unlike rootkit persistence.","Firmware and kernel infection survive even OS reinstallation.","This is basic resilience, not deep persistence.","This is a separate post-exploitation technique."]},
  {id:580,domain:G,question:"What is the difference between a false positive and a false negative in security?",options:["Flagging benign events vs missing real threats","False positives are always more dangerous","They describe the same detection error","False negatives are always rare in modern tools"],answer:0,explanation:"Both errors have costs: false positives waste analyst time and cause alert fatigue; false negatives miss real attacks. The balance depends on sensitivity/specificity tuning.",optionExplanations:["A false positive is a wrong alert; a false negative is a missed threat.","Neither is universally more dangerous than the other.","They are opposite types of detection error.","Even modern tools still miss sophisticated attacks."]},
  {id:581,domain:T,question:"What is a DDoS attack's distinction from a DoS attack?",options:["DDoS just uses more sophisticated techniques","DoS is always more powerful than DDoS","DDoS only targets distributed systems","Many systems flood a target at once"],answer:3,explanation:"DDoS attacks use thousands to millions of compromised systems — blocking one IP stops nothing; defending requires upstream scrubbing, anycast, or anti-DDoS services.",optionExplanations:["Sophistication isn't the distinction; source distribution is.","DDoS is generally more powerful due to distributed volume.","The distinction is source distribution, not target type.","Many sources make blocking a single IP ineffective."]},
  {id:582,domain:A,question:"What is a protocol analyzer (packet sniffer)?",options:["A device that blocks disallowed protocols inline","Capturing and analyzing network packets","A tool for tuning protocol performance","A tool analyzing protocol design for flaws"],answer:1,explanation:"Wireshark, tcpdump, and Zeek capture packets for troubleshooting, protocol analysis, incident investigation, and security monitoring — but attackers also use them to intercept credentials.",optionExplanations:["This is a firewall or IPS function, not passive capture.","Sniffers capture and decode packets for visibility.","This is performance tuning, not packet capture.","This is protocol design review, not live traffic capture."]},
  {id:583,domain:O,question:"What is vulnerability disclosure and coordinated disclosure?",options:["Disclosing only to government agencies","Notifying the vendor first, then disclosing publicly","Sharing details with researchers, not the vendor","Publishing every flaw immediately and publicly"],answer:1,explanation:"Coordinated disclosure (responsible disclosure) gives vendors typically 90 days (Google Project Zero standard) to patch before researchers publish — balancing public safety with research openness.",optionExplanations:["Standard coordinated disclosure notifies the vendor, not just government.","Vendors get time to patch before public disclosure.","Skipping the vendor is closer to full disclosure.","Immediate public disclosure is full disclosure, not coordinated."]},
  {id:584,domain:T,question:"What is an XML external entity (XXE) injection?",options:["Exploiting XML parsers via entities","Bypassing authentication built with XML","Injecting XML into database queries","Injecting entities into an XML database"],answer:0,explanation:"XXE exploits XML parsers that process external entity declarations — attackers can read /etc/passwd, internal network files, or make the server send requests to internal services.",optionExplanations:["XXE abuses external entity processing to read files or cause DoS.","XXE may enable this, but it's defined by entity processing.","This is a database injection attack, not XXE.","This confuses XML databases with XML parser exploitation."]},
  {id:585,domain:G,question:"What is the role of an Online Certificate Status Protocol (OCSP) responder?",options:["A service reporting certificate expiration dates","A protocol for automatic certificate renewal","A server issuing new certificates","A service providing real-time revocation status"],answer:3,explanation:"OCSP provides faster, smaller revocation checks than CRLs — OCSP stapling has the server cache and serve the OCSP response, reducing latency and improving privacy.",optionExplanations:["Expiration is checked from the certificate itself, not OCSP.","Renewal is handled by the CA, not OCSP.","Issuance is a CA function, not OCSP's role.","OCSP answers revocation queries faster than downloading a full CRL."]},
  {id:586,domain:P,question:"What is data tokenization?",options:["Swapping sensitive data for a token","Assigning tokens to represent access rights","Converting an asset into a blockchain token","Issuing short-lived post-login auth tokens"],answer:0,explanation:"Payment tokenization (credit card PANs replaced with tokens) means merchants never store actual card numbers — a breach of the merchant system exposes only worthless tokens.",optionExplanations:["Tokens replace sensitive values while a vault maps them back.","This is access authorization, unrelated to data protection.","This is blockchain asset tokenization, a different concept.","This is session authentication, not data protection."]},
  {id:587,domain:A,question:"What is an endpoint detection and response (EDR) platform?",options:["Continuous endpoint monitoring, investigation, and response","A patch deployment tracking platform","An endpoint inventory management platform","Traditional signature-based antivirus"],answer:0,explanation:"EDR (CrowdStrike Falcon, SentinelOne, Microsoft Defender for Endpoint) records every process, file change, network connection, and registry modification — enabling threat hunting and incident response.",optionExplanations:["EDR records telemetry and enables threat hunting and response.","This is patch management, not threat detection.","This is MDM or UEM inventory, not security detection.","Antivirus is signature-based; EDR adds behavioral detection and response."]},
  {id:588,domain:O,question:"What is the role of a CISO (Chief Information Security Officer)?",options:["A compliance tracking manager","The executive leading the IT department","The executive owning enterprise security and risk","The manager overseeing information storage systems"],answer:2,explanation:"The CISO translates technical security risk into business terms for the board, owns the security strategy, manages the security team, and is accountable for the security posture.",optionExplanations:["Compliance is one responsibility, not the entire CISO role.","IT leadership is typically the CIO's role, not the CISO's.","The CISO owns security strategy and reports risk to the board.","This is storage administration, not executive security leadership."]},
  {id:589,domain:T,question:"What is a malvertising attack?",options:["Malicious code delivered through ad networks","Fake malware removal service scams","Openly marketing malware removal products","Deceptive ads tricking users into disclosing data"],answer:0,explanation:"Malvertising compromises advertising networks to serve malicious ads on legitimate sites (New York Times, BBC have been affected) — users don't need to click; drive-by downloads trigger automatically.",optionExplanations:["Malvertising injects malicious code into legitimate ad networks.","This is scareware, a different scam technique.","This is unrelated legitimate marketing activity.","This is phishing-style deception, not malvertising's delivery method."]},
  {id:590,domain:G,question:"What is Perfect Forward Secrecy (PFS) achieved through?",options:["Using perfect hash functions for session keys","A fresh key exchange each session","Distributing one long-term key across servers","Reusing the same session key repeatedly"],answer:1,explanation:"ECDHE generates a new key pair for every TLS session — even if an attacker captures all TLS traffic and later steals the server private key, past sessions cannot be decrypted.",optionExplanations:["Hash functions aren't key exchange mechanisms.","ECDHE or DHE creates a fresh key each session, protecting past traffic.","This doesn't achieve forward secrecy at all.","Reusing keys defeats forward secrecy entirely."]},
  {id:591,domain:T,question:"What is a padding oracle attack?",options:["Exploiting padding bugs in smart contracts","Brute-forcing passwords with cloud oracles","Misconfigured padding in an Oracle database","Decryption errors leaking plaintext"],answer:3,explanation:"POODLE and BEAST exploited padding oracle vulnerabilities in SSL/TLS — the oracle's different error responses for bad padding vs. bad MAC leaked decryption information.",optionExplanations:["This is blockchain security, unrelated to padding oracles.","This confuses cloud computing with the oracle attack concept.","This confuses the Oracle database vendor with the cryptographic term.","Different error responses to bad padding leak plaintext bits."]},
  {id:592,domain:A,question:"What is serverless computing security?",options:["Securing VMs inside a shared hypervisor","Securing fully decommissioned physical servers","A model with literally no servers at all","Securing FaaS permissions, injection risk, and dependencies"],answer:3,explanation:"Serverless (AWS Lambda, Azure Functions) shifts infrastructure security to the provider but creates new risks: overprivileged IAM roles, function event injection, and insecure dependencies.",optionExplanations:["This is VM-level security, not FaaS.","This is unrelated to serverless computing.","Servers still exist, just managed by the provider.","Serverless security addresses IAM roles, event injection, and dependencies."]},
  {id:593,domain:O,question:"What is a security dashboard?",options:["A vehicle instrument panel for patrol teams","A tool for scheduling security staff shifts","A live view of security posture","A panel for operating security cameras"],answer:2,explanation:"Security dashboards (in SIEM, SOC platforms) aggregate metrics like open incidents, vulnerability counts, patch compliance, and detection rate — enabling rapid situational awareness.",optionExplanations:["This is a physical vehicle instrument, unrelated to cyber dashboards.","This is workforce scheduling, not security metrics.","Dashboards aggregate alerts, incidents, and compliance metrics.","This is a camera control panel, a physical security tool."]},
  {id:594,domain:P,question:"What is privacy-preserving analytics?",options:["Analyzing data without exposing individuals","Doing analytics work secretly and undisclosed","Analyzing only internally owned company data","Deleting personal data only after analysis"],answer:0,explanation:"Differential privacy (used by Apple, Google for telemetry) adds calibrated noise to aggregate results, preventing individual re-identification while preserving statistical accuracy.",optionExplanations:["Techniques like differential privacy add noise to protect individuals.","Secrecy alone doesn't protect the underlying personal data.","Data ownership doesn't by itself preserve privacy.","Deleting data afterward doesn't protect it during analysis."]},
  {id:595,domain:G,question:"What is a trojan access tool (RAT — Remote Access Trojan)?",options:["Malware giving attackers full remote control","A legitimate remote support desktop client","A sandbox tool for analyzing trojans remotely","A legitimate admin tool like SSH or RDP"],answer:0,explanation:"RATs (DarkComet, njRAT, Poison Ivy) provide attackers complete access — they can see the screen, record keystrokes, access files, and use the system as a platform for further attacks.",optionExplanations:["RATs give attackers covert full access, including keylogging.","Legitimate remote support tools are authorized, unlike RATs.","This is malware analysis tooling, not the malware itself.","SSH and RDP are legitimate authorized tools, unlike RATs."]},
  {id:596,domain:T,question:"What is BGP (Border Gateway Protocol) security risk?",options:["BGP has been fully deprecated and replaced","BGP lacks authentication, enabling route hijacking","BGP's risks are only theoretical","BGP creates flaws in all router hardware"],answer:1,explanation:"BGP route hijacking (like the 2008 Pakistan Telecom incident that took down YouTube globally) exploits BGP's trust model — RPKI (Resource Public Key Infrastructure) is the primary mitigation.",optionExplanations:["BGP remains the internet's primary routing protocol today.","BGP has no cryptographic check on route announcements.","Route hijacking has caused real, observed internet outages.","The risk is routing-specific, not general hardware flaws."]},
  {id:597,domain:A,question:"What is a security boundary?",options:["A regulatory scope boundary","A boundary of team job responsibilities","A point where trust level or policy changes","A physical perimeter fence around a facility"],answer:2,explanation:"Security boundaries determine where controls must be applied — firewalls at network boundaries, data classification at data access boundaries, encryption at transmission boundaries.",optionExplanations:["This is compliance scope, not an architectural boundary.","This is organizational responsibility, not a technical boundary.","Controls apply where trust context changes, like network zones.","Boundaries can be logical as well as physical."]},
  {id:598,domain:O,question:"What is a security control framework?",options:["A platform for managing software licenses","A catalog of security controls","A government-mandated regulatory requirement","A physical rack for mounting hardware"],answer:1,explanation:"CIS Controls, NIST 800-53, ISO 27001 Annex A provide control catalogs — organizations select and implement controls based on risk and compliance requirements.",optionExplanations:["This is license management, a narrow IT task.","Frameworks like CIS Controls provide libraries organizations select from.","Many frameworks are voluntary standards, not government mandates.","This is physical equipment mounting, unrelated to controls."]},
  {id:599,domain:T,question:"What is a race condition vulnerability?",options:["Exploiting timing between a check and its use","General slowdown under heavy load","A bug in racing simulation games","A flaw triggered only by legitimate simultaneous requests"],answer:0,explanation:"TOCTOU (Time of Check to Time of Use) race conditions occur when security checks and resource use have a window an attacker can exploit — changing a file between the check and the use.",optionExplanations:["TOCTOU flaws let attackers exploit the gap between check and use.","This is a performance issue, not a security timing flaw.","This is a domain-specific bug, unrelated to concurrency security.","Legitimate concurrent requests alone don't create the vulnerability."]},
  {id:600,domain:G,question:"What is security through obscurity?",options:["Using obscure, undocumented protocols deliberately","Relying on secrecy instead of proven security","A valid strategy based entirely on secrecy","Encrypting security tool configuration files"],answer:1,explanation:"Kerckhoffs' principle states security should depend only on key secrecy, not algorithm obscurity — attackers can reverse-engineer systems, but they can't steal a well-protected key.",optionExplanations:["This is one narrow form, not the general concept.","Design secrecy fails once details are discovered or leaked.","Obscurity alone is not considered sufficient security.","This is a legitimate separate practice, not obscurity itself."]},
  {id:601,domain:T,question:"What is a watering hole malware delivery chain?",options:["Malware spread via streaming platforms","Malware spread through water utility networks","A compromised trusted website that silently infects visitors","Malware infecting water treatment plants"],answer:2,explanation:"APT groups use watering holes for targeted attacks — compromising industry-specific sites (security conference sites, defense contractor portals) to reach specific targets.",optionExplanations:["Streaming platforms aren't the defining vector; watering holes compromise any site the target visits.","Water utility networks are OT targets, unrelated to this web-based malware technique.","Attackers compromise a site the target visits and inject exploit code to auto-infect visitors.","Water treatment systems are OT targets, a different category from web-based watering hole attacks."]},
  {id:602,domain:A,question:"What is a hardware-based VPN vs. software-based VPN?",options:["Hardware VPNs are inherently more secure by design","Incompatible protocols that can't interoperate","Dedicated appliances for higher throughput","Just a cost difference, nothing more"],answer:2,explanation:"Hardware VPNs (Cisco ASA, Palo Alto) handle high-throughput enterprise connections; software VPNs (OpenVPN, WireGuard) offer flexibility and lower cost for smaller deployments.",optionExplanations:["Security depends on configuration and protocols, not simply on hardware versus software implementation.","Both types typically use standard protocols like IPsec, allowing them to interoperate.","Hardware VPN appliances use dedicated processors, giving higher throughput than shared-CPU software VPNs.","Cost differs, but performance and flexibility are the more significant technical tradeoffs."]},
  {id:603,domain:O,question:"What is the difference between a vulnerability assessment and a risk assessment?",options:["Simply two different names for the same identical process","Technical weaknesses vs. business impact","Vulnerability assessments are always more comprehensive in scope","Risk assessments run only once annually"],answer:1,explanation:"Vulnerability assessments find the 'what' (SQL injection in the web app); risk assessments determine the 'so what' (potential for customer data breach with regulatory and reputational impact).",optionExplanations:["They are distinct processes with different scopes and outputs, not interchangeable names.","Vulnerability assessments find technical flaws; risk assessments translate them into business impact.","Neither is universally more comprehensive; each covers a different dimension of security.","Assessment frequency is set by policy, not a fixed rule distinguishing the two."]},
  {id:604,domain:T,question:"What is a time-of-check to time-of-use (TOCTOU) race condition?",options:["Checking the system clock before allowing any use","Gap between security check and use","A timing attack targeting login systems only","A flaw found only in NTP protocols"],answer:1,explanation:"Classic example: a program checks if file is readable, then reads it — attacker swaps a symlink between check and read, causing the program to read a sensitive file with elevated privileges.",optionExplanations:["Checking a clock is unrelated; TOCTOU concerns the gap between verification and action.","TOCTOU exploits the window between checking a condition and acting on it.","Login timing attacks are a different technique from this resource-state race condition.","TOCTOU is a general non-atomic check-then-use flaw, not specific to NTP."]},
  {id:605,domain:G,question:"What is the role of a trust anchor in PKI?",options:["Anchoring ongoing business relationships and contracts","A trusted root certificate accepted without further verification","The lowest-trust certificate in the hierarchy","The single most trusted org certificate"],answer:1,explanation:"Browsers ship with ~100 trusted root CAs — each is a trust anchor. Compromise of a root CA (like DigiNotar in 2011) undermines trust in all certificates it issued.",optionExplanations:["Business relationship anchoring is unrelated; PKI trust anchors are cryptographic trust foundations.","A trust anchor, like a root CA, is trusted by relying parties without further checks.","Trust anchors sit at the top, not bottom, of the certificate hierarchy.","Trust anchors are typically the root CA itself, described as the accepted starting point of trust."]},
  {id:606,domain:P,question:"What is a legitimate interest assessment (LIA)?",options:["Weighing business goals against privacy risk","Calculating applicable loan interest rates for personal data","A standard legal review of business interests","Assessing how legitimate a company appears to be"],answer:0,explanation:"A proper LIA documents the processing purpose, confirms no less-intrusive alternative exists, and demonstrates that privacy-respecting individuals would expect this processing.",optionExplanations:["An LIA weighs an organization's legitimate interest against individuals' privacy rights.","Financial interest rates are unrelated to this GDPR legal-basis assessment.","General business interest review is corporate governance, distinct from a GDPR-specific LIA.","Market legitimacy is a reputation concept, not this structured GDPR compliance process."]},
  {id:607,domain:A,question:"What is network traffic shaping in security?",options:["Restructuring the physical shape of data packets","Physically routing network cabling along a path","Limiting bandwidth to reduce attack impact","Setting access policies for different user groups"],answer:2,explanation:"Traffic shaping (QoS controls) can limit bandwidth available to DDoS traffic, prioritize critical business traffic during attacks, and restrict high-bandwidth applications from consuming all capacity.",optionExplanations:["Packet structure is a protocol engineering concern, not traffic shaping.","Cable routing is physical design, unrelated to managing traffic volume.","Traffic shaping controls bandwidth and flow to limit bandwidth-consuming attacks.","Access policy configuration is an access-control concern, not traffic shaping."]},
  {id:608,domain:O,question:"What is security metrics benchmarking?",options:["A raw technical benchmark of software speed","Rating individual staff against named competitors","Comparing metrics against industry peers","Benchmark testing of commercial security tools"],answer:2,explanation:"Benchmarking shows whether 72-hour average patching time is good or poor for the industry — peer comparison motivates improvement and helps justify security budget to executives.",optionExplanations:["Software speed testing is capacity planning, not program-level benchmarking.","Individual staff comparison is an HR exercise, not security metrics benchmarking.","Benchmarking compares an organization's security metrics against peers to find improvement gaps.","Tool performance testing is vendor evaluation, not overall program benchmarking."]},
  {id:609,domain:T,question:"What is a pharming attack's primary defense?",options:["DNSSEC adding cryptographic signatures to DNS records","Relying on a commercial VPN service","Relying on local antivirus software","Enabling two-factor authentication everywhere"],answer:0,explanation:"DNSSEC (DNS Security Extensions) signs DNS records so resolvers can detect tampered or forged DNS responses — defeating DNS cache poisoning and pharming at the protocol level.",optionExplanations:["DNSSEC signs DNS records so resolvers can detect tampered responses, defeating pharming.","VPNs protect traffic routing but don't prevent DNS-level poisoning.","Local antivirus doesn't address DNS-level manipulation, the actual root cause of pharming.","2FA protects accounts after login but doesn't stop victims reaching a poisoned DNS destination."]},
  {id:610,domain:G,question:"What is a cryptographic hash collision?",options:["An unexpected calculation error during hash computation","The same hash output across repeated runs","Two different inputs sharing one hash","Two different algorithms producing identical output"],answer:2,explanation:"SHA-1 collision was demonstrated in 2017 (SHAttered) — two different PDF files with identical SHA-1 hashes. This enabled forged digital signatures, leading to SHA-1 deprecation.",optionExplanations:["A collision isn't an error; it's a valid but unintended matching output.","Repeated identical output could suggest a broken RNG, not a hash collision.","A collision means two different inputs produce the same hash digest.","Two different algorithms matching is unrelated; a collision involves one algorithm, two inputs."]},
  {id:611,domain:T,question:"What is a network worm?",options:["A tool used for monitoring network traffic","A physical insect infestation damaging cabling","A cable management solution for server racks","Self-replicating malware needing no user interaction"],answer:3,explanation:"WannaCry used the EternalBlue SMB exploit to self-propagate across networks — infecting unpatched systems without any user action, creating massive parallel ransomware outbreaks.",optionExplanations:["Traffic monitoring is a legitimate function, not malware.","Insect infestation is a facilities issue, unrelated to malicious software.","Cable management is an infrastructure task, not malware.","Worms self-propagate across networks by exploiting flaws, without user action."]},
  {id:612,domain:A,question:"What is vulnerability scanning vs. penetration testing?",options:["Penetration testing performed only by automated tools","Scanning finds flaws; testing exploits them","The exact same process under two names","Scanning is inherently more thorough overall"],answer:1,explanation:"Scanning finds potential vulnerabilities (false positives possible); penetration testing confirms exploitability and impact (false positive elimination, actual risk demonstration).",optionExplanations:["Skilled human testers, not just tools, perform penetration testing.","Scanners identify potential vulnerabilities; pentesters manually exploit them to prove impact.","They are distinct activities with different methods and outputs.","Neither is universally more thorough; each covers different aspects of security."]},
  {id:613,domain:O,question:"What is an information security management system (ISMS)?",options:["Centralized license management for security tools","A ticketing system for tracking incidents","A dashboard unifying multiple security tools","A risk-based framework for security per ISO 27001"],answer:3,explanation:"An ISMS (ISO 27001) provides governance structure: policies, risk management, asset management, controls, incident management, and continual improvement through PDCA cycles.",optionExplanations:["License management is a narrow IT task, not the overarching ISMS.","Incident tracking is one component, not the entire ISMS.","Tool dashboards give visibility but aren't the governance framework itself.","An ISMS is a risk-based governance framework for information security, per ISO 27001."]},
  {id:614,domain:P,question:"What is data residency?",options:["The physical home mailing address of the data subject","Rules keeping data within a country's borders","Where data logically sits in a database schema","How long data is retained in a system"],answer:1,explanation:"Data residency requirements (Russia's Federal Law 149-FZ, China's data localization laws) require personal data to be stored on servers located within the country — affecting multinational cloud deployments.",optionExplanations:["A home address is personal data being protected, not the concept of residency.","Data residency requires personal data to stay within specific geographic boundaries.","Database schema location is a technical design concept, not geographic residency.","Retention duration is a separate policy concept from where data is stored."]},
  {id:615,domain:G,question:"What is a certificate chain of trust?",options:["Physical paper certificates chained together for archiving","Root CA down to end-entity certs","A dedicated network path for certificate delivery","The browser's preinstalled list of trusted roots"],answer:1,explanation:"Browsers trust root CAs → root CAs sign intermediate CAs → intermediate CAs sign website certificates — the chain enables trust without having every website cert directly signed by a root CA.",optionExplanations:["Physical paper chains don't exist in PKI; this is a cryptographic hierarchy.","The chain runs from root CA through intermediates to end-entity certificates.","Certificate delivery networks are unrelated to the trust hierarchy structure itself.","Trust stores hold root certificates, but the chain is the linking structure beneath them."]},
  {id:616,domain:T,question:"What is a blended threat?",options:["Multiple threat groups independently targeting one org","Combining malware, exploits, and social engineering","Multiple network-layer techniques overwhelming infrastructure at once","Attacks combining physical access and digital intrusion"],answer:1,explanation:"Modern APT attacks blend spear phishing (delivery) with zero-day exploits (installation) with legitimate tools (persistence) with encrypted C2 (communication) — no single control addresses all aspects.",optionExplanations:["Independent parallel attackers describe coincidence, not a single blended attack.","Blended threats combine diverse techniques into a single coordinated attack.","Multiple network-layer techniques describe DDoS variants, not blended threats generally.","Physical-digital hybrids are a related but distinct concept from blended threats."]},
  {id:617,domain:A,question:"What is a secure coding standard?",options:["A vendor-neutral developer security certification","Hardware security rules for developer workstations","Physical and logical dev-environment security rules","Rules like OWASP, CERT, or CWE for secure coding"],answer:3,explanation:"OWASP Top 10 coding guidance, CERT Secure Coding Standards, and CWE (Common Weakness Enumeration) provide specific rules preventing SQL injection, buffer overflows, and other common vulnerabilities.",optionExplanations:["A certification validates knowledge; a coding standard is the set of rules developers follow.","Workstation hardening rules protect endpoints, not the code being written.","Development environment security addresses infrastructure, not the code's own vulnerabilities.","Standards like OWASP, CERT, and CWE define rules for writing secure code."]},
  {id:618,domain:O,question:"What is a network flow record (NetFlow, IPFIX)?",options:["A network topology diagram of traffic paths between sites","Physical cable-run and patch panel logs","Full packet capture with complete payloads","Metadata like IPs, ports, and byte counts"],answer:3,explanation:"Flow records (NetFlow, sFlow, IPFIX) enable 'who talked to whom, when, and how much' analysis at scale — impossible with full packet capture but sufficient to detect C2 beaconing, scanning, and data exfiltration.",optionExplanations:["Topology diagrams document physical layout, not collected communication metadata.","Cable-run logs are infrastructure documentation, unrelated to network flow data.","Full packet capture stores payload content, unlike lightweight flow records.","Flow records capture metadata like IPs and ports without payload content."]},
  {id:619,domain:P,question:"What is the right to restriction of processing under GDPR?",options:["Choosing which employees can access stored records","Pausing processing during a dispute","Enforcing maximum retention schedules for data","Withdrawing consent to halt all processing"],answer:1,explanation:"GDPR Article 18 allows data subjects to have their data 'frozen' during disputes — the data can't be deleted or further processed until the restriction is lifted.",optionExplanations:["Internal access control is a governance matter, not this data subject right.","Restriction of processing pauses use of data while a dispute is resolved.","Retention schedules are storage limitation, a separate GDPR principle.","Consent withdrawal stops future processing but doesn't describe this temporary freeze right."]},
  {id:620,domain:G,question:"What is an end-entity certificate?",options:["A leaf cert that cannot sign others","A backend API server certificate used exclusively for internal calls","A specialized certificate restricted only to protecting S/MIME email","A certificate placed on administrative hold by a CA"],answer:0,explanation:"End-entity (leaf) certificates are issued to specific subjects (websites, users, code signing) and are constrained from signing other certificates — unlike intermediate CAs which can issue certificates.",optionExplanations:["End-entity certificates sit at the bottom of the hierarchy and can't issue others.","Backend API certificates are one example of end-entity certs, not the full definition.","S/MIME certificates are only one type among many end-entity certificates.","Administrative hold describes a revocation state, not the end-entity position itself."]},
  {id:621,domain:O,question:"What is a security assessment scope?",options:["Regions feeding log data into a SIEM","Defined boundaries of what systems may be tested","Division of security duties across teams","Physical patrol territory assigned to guards"],answer:1,explanation:"Scope defines what's authorized — testing systems outside scope is unauthorized access. Scoping must be explicit in writing to protect testers legally and focus testing efforts.",optionExplanations:["SIEM coverage defines monitoring visibility, not authorized testing boundaries.","Scope defines which systems and tests are authorized, preventing unauthorized access.","Team responsibility division is organizational structure, not assessment scope.","Physical patrol areas are a facilities concept, unrelated to digital testing scope."]},
  {id:622,domain:T,question:"What is a supply chain attack vector distinction from other attacks?",options:["Physically intercepting and tampering with goods in transit before delivery","Exploiting trust in a vendor's software or services","Compromising procurement systems to redirect payments","Simultaneous campaigns against many competing suppliers"],answer:1,explanation:"Supply chain attacks are uniquely powerful because they exploit trust — targets don't scrutinize software from their trusted vendors the same way they'd scrutinize unknown software.",optionExplanations:["Physical interdiction is a hardware supply chain concern, distinct from software trust exploitation.","Supply chain attacks exploit the trust targets place in vendor software or services.","Payment redirection describes business email compromise, not this trust-based technique.","Targeting many suppliers describes breadth, not the defining trust-exploitation characteristic."]},
  {id:623,domain:A,question:"What is a software bill of materials (SBOM)?",options:["An itemized invoice for software licensing fees","A machine-readable inventory of software components","An invoice for penetration testing services rendered","A list of developer tools installed locally"],answer:1,explanation:"Biden's 2021 Executive Order required SBOMs for federal software — Log4Shell demonstrated why: organizations couldn't tell which of their products used Log4j without an SBOM.",optionExplanations:["Licensing invoices are financial records, not a component inventory.","An SBOM is a machine-readable inventory of a software product's components and dependencies.","Testing service invoices are vendor billing, unrelated to component inventories.","Developer tool lists are IT asset records, not the shipped product's dependency list."]},
  {id:624,domain:P,question:"What is cross-border data transfer under GDPR's adequacy decision?",options:["A formal bilateral treaty facilitating law-enforcement evidence sharing","A company's own internal self-assessment of controls","An EU ruling that protections are adequate","A network bandwidth sufficiency determination for transfers"],answer:2,explanation:"EU adequacy decisions (UK, Japan, Canada, etc.) permit free data flow similar to within the EU — without adequacy, organizations need SCCs, BCRs, or other transfer mechanisms.",optionExplanations:["Law-enforcement treaties address evidence sharing, unrelated to commercial data transfer rules.","Self-assessment is internal review, not a formal European Commission determination.","An adequacy decision is the European Commission's ruling that a country's protections are equivalent.","Bandwidth sufficiency is a network engineering concern, unrelated to legal data protection."]},
  {id:625,domain:G,question:"What is a digital certificate's validity period?",options:["The timeframe before a certificate must be renewed","Time elapsed since a certificate was issued","Time left before a private key rotates","A CA's contracted support-response window"],answer:0,explanation:"Short validity periods (industry moving to 90-day certificates) limit exposure if a key is compromised — an expired certificate is rejected even without revocation.",optionExplanations:["Validity period is the window during which a certificate is considered valid before renewal.","Age since issuance isn't embedded in the cert; validity uses fixed start and end dates.","Private key rotation is a separate organizational policy, not the certificate's own validity window.","CA support commitments are contractual terms, unrelated to the cryptographic validity window."]},
  {id:626,domain:T,question:"What is a SSRF (Server-Side Request Forgery)?",options:["A design pattern validating all outbound server requests","Server tricked into requesting arbitrary URLs","An allowlist mechanism restricting all outbound requests","A 403 error from misconfigured cloud storage"],answer:1,explanation:"SSRF in cloud environments is especially dangerous — attackers can query cloud metadata endpoints (169.254.169.254) to steal IAM credentials, as in the 2019 Capital One breach.",optionExplanations:["Request validation is the defense against SSRF, not the vulnerability itself.","SSRF tricks a server into making requests to arbitrary attacker-chosen URLs.","Outbound allowlisting is a mitigation, not the vulnerability being described.","A storage access error is a configuration issue, not the SSRF vulnerability class."]},
  {id:627,domain:A,question:"What is identity federation?",options:["Merging duplicate accounts into a single identity","Using one login across trusted organizations","Synchronizing authorization policies across multiple partner companies","A consortium sharing threat intelligence standards"],answer:1,explanation:"SAML and OIDC enable federation — a university student uses their university login to access a partner research institution's resources without a separate account.",optionExplanations:["Account merging eliminates duplicates; federation instead links separate identity stores via trust.","Identity federation lets one login be trusted across multiple organizations.","Policy synchronization addresses authorization rules, not authentication trust relationships.","Threat intelligence sharing consortia are unrelated to authentication federation."]},
  {id:628,domain:O,question:"What is a risk treatment option in cybersecurity?",options:["Applying identical controls to every identified risk","An incident response plan for containment steps","Mental-health and burnout support for SOC analysts","Accept, avoid, mitigate, or transfer risk"],answer:3,explanation:"Risk transfer (cyber insurance) shifts financial impact; avoidance eliminates the risky activity; mitigation reduces probability or impact; acceptance is conscious tolerance of residual risk.",optionExplanations:["Uniform controls ignore risk-based prioritization central to risk treatment.","Incident response addresses active incidents, not proactive risk treatment decisions.","Analyst wellbeing support is an HR function, unrelated to risk treatment options.","Risk treatment options are accept, avoid, mitigate, or transfer."]},
  {id:629,domain:T,question:"What is a physical security attack known as shoulder surfing?",options:["Observing a screen or keypad to steal data","Tampering with shoulder-height security cameras","Using someone's body to climb a fence","Casually glancing at a coworker's desk"],answer:0,explanation:"Shoulder surfing is especially effective at ATMs, airports, and coffee shops — privacy screens (polarizing filters), position awareness, and cover when typing PINs are countermeasures.",optionExplanations:["Shoulder surfing observes a victim's screen or input to steal sensitive data.","Camera tampering is a different physical security attack, not observation-based.","Using a person as a climbing aid is a different physical-access technique.","Casual glancing without intent to steal data isn't shoulder surfing."]},
  {id:630,domain:G,question:"What is a preimage attack in cryptography?",options:["Generating a preview thumbnail of an encrypted file without decrypting it","Timing differences between encryption operations on inputs","Compressing data into a smaller format before encryption","Reversing a hash to find its input"],answer:3,explanation:"Preimage resistance means finding any input that hashes to a given output should be computationally infeasible — a broken hash function enables forging signatures without the private key.",optionExplanations:["Thumbnail generation is a file-management feature, unrelated to hash cryptanalysis.","Timing-based cryptanalysis is a side-channel attack, distinct from preimage attacks.","Pre-encryption compression is a data-preparation step, not a hash attack.","A preimage attack finds any input that produces a given hash output."]},
];
